/** Exhaustive cross-check over a documented, symmetry-reduced runtime universe. */
class BoundedRuntimeUniverseTest {
	private static final ValueFactory VF = SimpleValueFactory.getInstance();
	private static final IRI R0 = VF.createIRI("urn:bounded:r0");
	private static final IRI R1 = VF.createIRI("urn:bounded:r1");
	private static final IRI R2 = VF.createIRI("urn:bounded:r2");
	private static final IRI P = VF.createIRI("urn:bounded:p");
	private static final IRI Q = VF.createIRI("urn:bounded:q");
	private static final IRI GRAPH = VF.createIRI("urn:bounded:g");
	private static final BNode B0 = VF.createBNode("bounded-b0");
	private static final Literal L0 = VF.createLiteral("zero");

	@Test
	void everyPositiveVerdictMatchesEveryRuntimeEvaluation() {
		List<NamedExpression> expressions = expressions();
		Map<ContextMode, List<EvaluationCase>> cases = Map.of(
				ContextMode.TOP_LEVEL_EMPTY, evaluationCases(false),
				ContextMode.ALL_BINDINGS, evaluationCases(true));
		Map<ContextMode, Map<String, List<EvaluationOutcome>>> outcomes = new LinkedHashMap<>();
		for (ContextMode context : ContextMode.values()) {
			outcomes.put(context, evaluateAll(expressions, cases.get(context)));
		}

		int pairProfiles = 0;
		int equivalentVerdicts = 0;
		int normalizationCertificates = 0;
		for (ContextMode context : ContextMode.values()) {
			for (ObservationMode observation : ObservationMode.values()) {
				CheckOptions options = CheckOptions.builder()
						.semanticsTarget(SemanticsTarget.RDF4J_RUNTIME)
						.observationMode(observation)
						.contextMode(context)
						.boundedCounterexampleSearch(false)
						.build();
				AlgebraEquivalenceChecker checker = new AlgebraEquivalenceChecker(options);
				ProofKernel kernel = new ProofKernel(options);
				for (int leftIndex = 0; leftIndex < expressions.size(); leftIndex++) {
					for (int rightIndex = leftIndex; rightIndex < expressions.size(); rightIndex++) {
						NamedExpression left = expressions.get(leftIndex);
						NamedExpression right = expressions.get(rightIndex);
						EquivalenceResult result = checker.check(left.expression().clone(), right.expression().clone());
						pairProfiles++;
						if (!result.isEquivalent()) {
							continue;
						}

						equivalentVerdicts++;
						EquivalenceEvidence evidence = result.getEvidence().orElseThrow();
						assertTrue(
								kernel.verify(left.expression().clone(), right.expression().clone(), evidence),
								() -> profile(context, observation, left, right) + " kernel replay failed");
						if (evidence instanceof NormalizationProof proof) {
							normalizationCertificates++;
							assertTrue(proof.getCertificate().isPresent(),
									() -> profile(context, observation, left, right) + " has no certificate");
						}

						List<EvaluationOutcome> leftOutcomes = outcomes.get(context).get(left.name());
						List<EvaluationOutcome> rightOutcomes = outcomes.get(context).get(right.name());
						assertEquals(leftOutcomes.size(), rightOutcomes.size());
						for (int caseIndex = 0; caseIndex < leftOutcomes.size(); caseIndex++) {
							int checkedCase = caseIndex;
							assertTrue(
									leftOutcomes.get(caseIndex).sameAs(rightOutcomes.get(caseIndex), observation),
									() -> profile(context, observation, left, right)
											+ " differs on " + cases.get(context).get(checkedCase).getLabel()
											+ ": " + leftOutcomes.get(checkedCase)
											+ " != " + rightOutcomes.get(checkedCase));
						}
					}
				}
			}
		}

		int expectedPairProfiles = ContextMode.values().length
				* ObservationMode.values().length
				* expressions.size()
				* (expressions.size() + 1)
				/ 2;
		assertEquals(expectedPairProfiles, pairProfiles);
		assertTrue(equivalentVerdicts > expressions.size() * ObservationMode.values().length,
				"universe did not exercise non-reflexive positive verdicts");
		assertTrue(normalizationCertificates > 0, "universe did not exercise normalization certificates");
		System.out.println("[bounded-runtime] expressions=" + expressions.size()
				+ " topLevelCases=" + cases.get(ContextMode.TOP_LEVEL_EMPTY).size()
				+ " allBindingCases=" + cases.get(ContextMode.ALL_BINDINGS).size()
				+ " pairProfiles=" + pairProfiles
				+ " equivalentVerdicts=" + equivalentVerdicts
				+ " normalizationCertificates=" + normalizationCertificates);
	}

	private static Map<String, List<EvaluationOutcome>> evaluateAll(
			List<NamedExpression> expressions,
			List<EvaluationCase> cases) {
		Rdf4jEvaluator evaluator = new Rdf4jEvaluator();
		Map<String, List<EvaluationOutcome>> outcomes = new LinkedHashMap<>();
		for (NamedExpression expression : expressions) {
			List<EvaluationOutcome> expressionOutcomes = new ArrayList<>();
			for (EvaluationCase evaluationCase : cases) {
				EvaluationAttempt attempt = evaluator.evaluate(expression.expression(), evaluationCase, 128);
				assertTrue(attempt.isComplete(),
						() -> expression.name() + " exceeded the bounded result universe on "
								+ evaluationCase.getLabel());
				expressionOutcomes.add(attempt.getOutcome().orElseThrow());
			}
			assertFalse(outcomes.containsKey(expression.name()), "duplicate expression label " + expression.name());
			outcomes.put(expression.name(), List.copyOf(expressionOutcomes));
		}
		return Map.copyOf(outcomes);
	}

	private static List<NamedExpression> expressions() {
		StatementPattern pattern = pattern();
		List<NamedExpression> expressions = new ArrayList<>();
		expressions.add(named("empty", new EmptySet()));
		expressions.add(named("unit", new SingletonSet()));
		expressions.add(named("values-empty", values(List.of())));
		expressions.add(named("values-unit", values(List.of(EmptyBindingSet.getInstance()))));
		expressions.add(named("values-r0", values(List.of(row("o", R0)))));
		expressions.add(named("values-r0-r0", values(List.of(row("o", R0), row("o", R0)))));
		expressions.add(named("pattern", pattern.clone()));
		expressions.add(named("pattern-r0", new StatementPattern(Var.of("s", R0), Var.of("p", P), Var.of("o"))));
		expressions.add(named("filter-true", new Filter(pattern.clone(), new ValueConstant(VF.createLiteral(true)))));
		expressions.add(named("filter-false", new Filter(pattern.clone(), new ValueConstant(VF.createLiteral(false)))));
		expressions.add(named("filter-error", new Filter(pattern.clone(), new ValueConstant(R0))));
		expressions.add(named("join-unit-right", new Join(pattern.clone(), new SingletonSet())));
		expressions.add(named("join-unit-left", new Join(new SingletonSet(), pattern.clone())));
		expressions.add(named("join-empty", new Join(pattern.clone(), new EmptySet())));
		expressions.add(named("union-empty-right", new Union(pattern.clone(), new EmptySet())));
		expressions.add(named("union-empty-left", new Union(new EmptySet(), pattern.clone())));
		expressions.add(named("union-self", new Union(pattern.clone(), pattern.clone())));
		expressions.add(named("distinct", new Distinct(pattern.clone())));
		expressions.add(named("distinct-nested", new Distinct(new Distinct(pattern.clone()))));
		expressions.add(named("reduced", new Reduced(pattern.clone())));
		expressions.add(named("minus-empty-right", new Difference(pattern.clone(), new EmptySet())));
		expressions.add(named("minus-empty-left", new Difference(new EmptySet(), pattern.clone())));
		expressions.add(named("leftjoin-empty-right", new LeftJoin(pattern.clone(), new EmptySet())));
		expressions.add(named("leftjoin-empty-left", new LeftJoin(new EmptySet(), pattern.clone())));
		expressions.add(named("projection", new Projection(
				pattern.clone(),
				new ProjectionElemList(new ProjectionElem("o")))));
		expressions.add(named("order", new Order(pattern.clone(), new OrderElem(Var.of("o")))));
		expressions.add(named("slice", new Slice(pattern.clone(), 0, 1)));
		return List.copyOf(expressions);
	}

	private static List<EvaluationCase> evaluationCases(boolean includeIncomingBindings) {
		List<List<Statement>> datasets = List.of(
				List.of(),
				List.of(VF.createStatement(R0, P, R1)),
				List.of(VF.createStatement(R0, P, R1), VF.createStatement(R0, P, L0)),
				List.of(VF.createStatement(B0, P, R2), VF.createStatement(R2, Q, L0)),
				List.of(VF.createStatement(R0, P, R1, GRAPH)));
		List<BindingSet> incomingBindings = new ArrayList<>();
		incomingBindings.add(EmptyBindingSet.getInstance());
		if (includeIncomingBindings) {
			incomingBindings.add(row("o", R1));
			incomingBindings.add(row("o", R2));
			incomingBindings.add(row("s", R0));
		}

		List<EvaluationCase> result = new ArrayList<>();
		for (int datasetIndex = 0; datasetIndex < datasets.size(); datasetIndex++) {
			for (int bindingIndex = 0; bindingIndex < incomingBindings.size(); bindingIndex++) {
				result.add(EvaluationCase.builder("d" + datasetIndex + "-b" + bindingIndex)
						.statements(datasets.get(datasetIndex))
						.initialBindings(incomingBindings.get(bindingIndex))
						.build());
			}
		}
		return List.copyOf(result);
	}

	private static BindingSetAssignment values(List<BindingSet> rows) {
		BindingSetAssignment assignment = new BindingSetAssignment();
		assignment.setDeclaredBindingNames(Set.of("o"));
		assignment.setBindingSets(rows);
		return assignment;
	}

	private static MapBindingSet row(String name, Value value) {
		MapBindingSet row = new MapBindingSet(1);
		row.setBinding(name, value);
		return row;
	}

	private static StatementPattern pattern() {
		return new StatementPattern(Var.of("s"), Var.of("p", P), Var.of("o"));
	}

	private static NamedExpression named(String name, TupleExpr expression) {
		return new NamedExpression(name, expression);
	}

	private static String profile(
			ContextMode context,
			ObservationMode observation,
			NamedExpression left,
			NamedExpression right) {
		return context + "/" + observation + " " + left.name() + " ~ " + right.name();
	}

	private record NamedExpression(String name, TupleExpr expression) {
	}
}
